using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6–10 alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "English", Abbreviation = "ENG" },
        new() { Id = 4, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses;

    public CatalogService()
    {
        _courses =
        [
            new() { Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, methods, and object-oriented design.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Ada Lovelace", InstructorBio = "Dr. Lovelace has 15 years of experience teaching introductory programming and is passionate about making computer science accessible to all students.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, CourseCode = "CS 301", Title = "Data Structures and Algorithms", Description = "Study of fundamental data structures (lists, trees, graphs, hash tables) and algorithm design techniques (divide and conquer, dynamic programming, greedy algorithms).", Credits = 4, Schedule = "Tue/Thu 10:30–11:45 AM", InstructorName = "Dr. Alan Turing", InstructorBio = "Dr. Turing specializes in algorithm analysis and computational complexity. He has published extensively on graph algorithms.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, CourseCode = "CS 450", Title = "Machine Learning", Description = "Introduction to machine learning concepts including supervised and unsupervised learning, neural networks, and model evaluation.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", InstructorName = "Dr. Grace Hopper", InstructorBio = "Dr. Hopper brings industry experience from leading ML teams at major tech companies before joining academia.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, CourseCode = "MATH 201", Title = "Linear Algebra", Description = "Vectors, matrices, linear transformations, eigenvalues, and applications to data science and engineering.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Emmy Noether", InstructorBio = "Dr. Noether is an award-winning mathematician known for making abstract algebra approachable and relevant.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, CourseCode = "MATH 305", Title = "Probability and Statistics", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 4, Schedule = "Tue/Thu 1:00–2:15 PM", InstructorName = "Dr. Carl Gauss", InstructorBio = "Dr. Gauss has authored three textbooks on statistics and consults for data-driven organizations.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, CourseCode = "ENG 101", Title = "Composition and Rhetoric", Description = "Develop college-level writing skills through essays, research papers, and peer workshops.", Credits = 3, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Prof. Maya Angelou", InstructorBio = "Prof. Angelou is a published author and writing coach with a passion for helping students find their voice.", DepartmentId = 3, DepartmentName = "English", IsFeatured = false },
            new() { Id = 7, CourseCode = "ENG 220", Title = "World Literature", Description = "Survey of major literary works from diverse cultures and time periods, exploring themes of identity, power, and art.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", InstructorName = "Prof. Chinua Achebe", InstructorBio = "Prof. Achebe is a literary scholar specializing in postcolonial literature and comparative narrative techniques.", DepartmentId = 3, DepartmentName = "English", IsFeatured = true },
            new() { Id = 8, CourseCode = "PHYS 201", Title = "Classical Mechanics", Description = "Newtonian mechanics, energy, momentum, rotational dynamics, and oscillations.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Isaac Newton", InstructorBio = "Dr. Newton combines rigorous theory with engaging demonstrations to bring physics to life.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, CourseCode = "PHYS 310", Title = "Quantum Physics", Description = "Wave-particle duality, Schrödinger equation, quantum states, and applications in modern technology.", Credits = 3, Schedule = "Tue/Thu 3:00–4:15 PM", InstructorName = "Dr. Richard Feynman", InstructorBio = "Dr. Feynman is renowned for his ability to explain complex quantum phenomena with clarity and humor.", DepartmentId = 4, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 10, CourseCode = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations, cultural exchanges, and turning points from antiquity through the late medieval period.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", InstructorName = "Dr. Howard Zinn", InstructorBio = "Dr. Zinn emphasizes diverse perspectives and primary source analysis in his teaching.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false },
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);
}

