@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<section class="hero">
    <h1>Welcome to the University Course Catalog</h1>
    <p>Explore our departments, browse courses, and enroll today.</p>
    <a href="/courses" class="btn-primary">Browse All Courses</a>
</section>

<section class="departments-section">
    <h2>Departments</h2>
    <div class="department-grid">
        @foreach (var dept in departments)
        {
            <a href="/courses?departmentId=@dept.Id" class="department-card">
                <strong>@dept.Abbreviation</strong>
                <span>@dept.Name</span>
            </a>
        }
    </div>
</section>

<section class="featured-section">
    <h2>Featured Courses</h2>
    <div class="course-grid">
        @foreach (var course in featuredCourses)
        {
            <div class="course-card">
                <span class="course-code">@course.CourseCode</span>
                <h3>@course.Title</h3>
                <p class="course-meta">@course.Credits credits · @course.DepartmentName</p>
                <p class="course-instructor">@course.InstructorName</p>
                <a href="/courses/@course.Id">View Details →</a>
            </div>
        }
    </div>
</section>

@code {
    private List<Department> departments = [];
    private List<Course> featuredCourses = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        featuredCourses = Catalog.GetFeaturedCourses();
    }
}

::deep .hero {
    text-align: center;
    padding: 3rem 1rem;
    background: linear-gradient(135deg, #e8eaf6, #c5cae9);
    border-radius: 8px;
    margin-bottom: 2rem;
}

::deep .hero h1 {
    margin: 0 0 0.5rem;
    color: #1a237e;
}

::deep .hero p {
    color: #333;
    margin-bottom: 1.5rem;
}

::deep .btn-primary {
    display: inline-block;
    background-color: #1a237e;
    color: white;
    padding: 0.75rem 1.5rem;
    border-radius: 4px;
    text-decoration: none;
    font-weight: 500;
}

::deep .btn-primary:hover {
    background-color: #283593;
}

::deep .departments-section,
::deep .featured-section {
    margin-bottom: 2.5rem;
}

::deep .departments-section h2,
::deep .featured-section h2 {
    margin-bottom: 1rem;
    color: #1a237e;
}

::deep .department-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(180px, 1fr));
    gap: 1rem;
}

::deep .department-card {
    display: flex;
    flex-direction: column;
    align-items: center;
    padding: 1.25rem;
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    text-decoration: none;
    color: #333;
    transition: box-shadow 0.2s;
}

::deep .department-card:hover {
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
}

::deep .department-card strong {
    font-size: 1.5rem;
    color: #1a237e;
}

::deep .course-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
    gap: 1.25rem;
}

::deep .course-card {
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
}

::deep .course-card .course-code {
    font-size: 0.8rem;
    font-weight: bold;
    color: #666;
    text-transform: uppercase;
}

::deep .course-card h3 {
    margin: 0.5rem 0;
    font-size: 1.1rem;
}

::deep .course-card .course-meta {
    font-size: 0.875rem;
    color: #666;
}

::deep .course-card .course-instructor {
    font-size: 0.875rem;
    font-style: italic;
    color: #555;
}

::deep .course-card a {
    display: inline-block;
    margin-top: 0.75rem;
    color: #1a237e;
    font-weight: 500;
    text-decoration: none;
}

::deep .course-card a:hover {
    text-decoration: underline;
}

