@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search courses, codes, or instructors..." class="search-input" />
    <select name="departmentId" class="dept-select">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-search">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-info">
                    <span class="course-code">@course.CourseCode</span>
                    <a href="/courses/@course.Id" class="course-title">@course.Title</a>
                    <span class="course-dept">@course.DepartmentName</span>
                </div>
                <div class="course-details">
                    <span>@course.Credits credits</span>
                    <span>@course.InstructorName</span>
                    <span>@course.Schedule</span>
                </div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = [];
    private List<Course> courses = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

::deep .filter-bar {
    display: flex;
    gap: 0.75rem;
    margin-bottom: 1.5rem;
    flex-wrap: wrap;
}

::deep .search-input {
    flex: 1;
    min-width: 200px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .dept-select {
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .btn-search {
    padding: 0.5rem 1.25rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-weight: 500;
}

::deep .btn-search:hover {
    background-color: #283593;
}

::deep .no-results {
    color: #666;
    font-style: italic;
    padding: 2rem 0;
}

::deep .course-list {
    display: flex;
    flex-direction: column;
    gap: 0.75rem;
}

::deep .course-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 1rem 1.25rem;
    background: white;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    flex-wrap: wrap;
    gap: 0.5rem;
}

::deep .course-row:hover {
    border-color: #1a237e;
}

::deep .course-info {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    flex-wrap: wrap;
}

::deep .course-info .course-code {
    font-weight: bold;
    font-size: 0.85rem;
    color: #666;
    background: #f0f0f0;
    padding: 0.2rem 0.5rem;
    border-radius: 3px;
}

::deep .course-info .course-title {
    font-weight: 600;
    color: #1a237e;
    text-decoration: none;
}

::deep .course-info .course-title:hover {
    text-decoration: underline;
}

::deep .course-info .course-dept {
    font-size: 0.85rem;
    color: #888;
}

::deep .course-details {
    display: flex;
    gap: 1.25rem;
    font-size: 0.875rem;
    color: #555;
}

::deep .breadcrumb {
    margin-bottom: 1.5rem;
    font-size: 0.9rem;
    color: #666;
}

::deep .breadcrumb a {
    color: #1a237e;
    text-decoration: none;
}

::deep .breadcrumb a:hover {
    text-decoration: underline;
}

::deep .course-detail header {
    margin-bottom: 2rem;
}

::deep .course-detail .course-code {
    display: inline-block;
    font-size: 0.85rem;
    font-weight: bold;
    color: #666;
    background: #f0f0f0;
    padding: 0.25rem 0.6rem;
    border-radius: 3px;
    margin-bottom: 0.5rem;
}

::deep .course-detail h1 {
    margin: 0.5rem 0 0;
    color: #1a237e;
}

::deep .detail-grid {
    display: grid;
    grid-template-columns: 1fr 320px;
    gap: 2rem;
    align-items: start;
}

@media (max-width: 768px) {
    ::deep .detail-grid {
        grid-template-columns: 1fr;
    }
}

::deep .description-section h2 {
    font-size: 1.25rem;
    margin-bottom: 0.75rem;
    color: #333;
}

::deep .description-section p {
    line-height: 1.7;
    color: #444;
}

::deep .info-sidebar {
    display: flex;
    flex-direction: column;
    gap: 1.25rem;
}

::deep .info-card {
    background: #f9f9f9;
    border: 1px solid #e0e0e0;
    border-radius: 8px;
    padding: 1.25rem;
}

::deep .info-card h3 {
    margin: 0 0 0.75rem;
    font-size: 1rem;
    color: #1a237e;
}

::deep .info-card dl {
    display: grid;
    grid-template-columns: auto 1fr;
    gap: 0.4rem 1rem;
    margin: 0;
}

::deep .info-card dt {
    font-weight: 600;
    color: #555;
    font-size: 0.9rem;
}

::deep .info-card dd {
    margin: 0;
    font-size: 0.9rem;
}

::deep .instructor-name {
    font-weight: 600;
    margin: 0 0 0.5rem;
}

::deep .instructor-bio {
    font-size: 0.9rem;
    line-height: 1.5;
    color: #555;
    margin: 0;
}

::deep .btn-enroll {
    display: block;
    text-align: center;
    background-color: #1a237e;
    color: white;
    padding: 0.75rem 1.5rem;
    border-radius: 4px;
    text-decoration: none;
    font-weight: 500;
}

::deep .btn-enroll:hover {
    background-color: #283593;
}

@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>✓ Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseName</strong> has been received.</p>
        <p>You will receive a confirmation via your university email.</p>
        <a href="/courses">← Browse More Courses</a>
    </div>
}
else
{
    <p class="form-intro">Fill out the form below to request enrollment in a course. All fields are required.</p>

    <form method="post" class="enrollment-form">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required maxlength="100" />
            @if (errors.ContainsKey(nameof(Model.StudentName)))
            {
                <span class="field-error">@errors[nameof(Model.StudentName)]</span>
            }
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g. ABC12345" />
            <small>6–10 alphanumeric characters (uppercase letters and digits)</small>
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <span class="field-error">@errors[nameof(Model.StudentId)]</span>
            }
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in allCourses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode — @course.Title</option>
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <span class="field-error">@errors[nameof(Model.CourseId)]</span>
            }
        </div>

        <button type="submit" class="btn-submit">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> allCourses = [];
    private Dictionary<string, string> errors = new();
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        allCourses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            ValidateAndSubmit();
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }

    private void ValidateAndSubmit()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            errors[nameof(Model.StudentName)] = "Name is required.";

        if (string.IsNullOrWhiteSpace(Model.StudentId))
            errors[nameof(Model.StudentId)] = "Student ID is required.";
        else if (!System.Text.RegularExpressions.Regex.IsMatch(Model.StudentId, @"^[A-Z0-9]{6,10}$"))
            errors[nameof(Model.StudentId)] = "Student ID must be 6–10 uppercase alphanumeric characters.";

        if (Model.CourseId <= 0)
            errors[nameof(Model.CourseId)] = "Please select a course.";

        if (errors.Count == 0)
        {
            var course = Catalog.GetCourse(Model.CourseId);
            selectedCourseName = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown";
            submitted = true;
        }
    }
}

::deep .form-intro {
    color: #555;
    margin-bottom: 1.5rem;
}

::deep .enrollment-form {
    max-width: 500px;
}

::deep .form-group {
    margin-bottom: 1.25rem;
}

::deep .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #333;
}

::deep .form-group input,
::deep .form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .form-group small {
    display: block;
    margin-top: 0.25rem;
    color: #888;
    font-size: 0.8rem;
}

::deep .field-error {
    display: block;
    margin-top: 0.25rem;
    color: #c62828;
    font-size: 0.85rem;
}

::deep .btn-submit {
    padding: 0.65rem 1.5rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
}

::deep .btn-submit:hover {
    background-color: #283593;
}

::deep .success-message {
    background: #e8f5e9;
    border: 1px solid #a5d6a7;
    border-radius: 8px;
    padding: 1.5rem;
    max-width: 500px;
}

::deep .success-message h2 {
    color: #2e7d32;
    margin: 0 0 0.75rem;
}

::deep .success-message p {
    margin: 0.5rem 0;
