@page "/enroll"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>

@if (submitted)
{
    <div class="success-message">
        <h2>✓ Request Submitted</h2>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for <strong>@selectedCourseName</strong> has been received.</p>
        <p>You will receive a confirmation via your university email.</p>
        <a href="/courses">← Browse More Courses</a>
    </div>
}
else
{
    <p class="form-intro">Fill out the form below to request enrollment in a course. All fields are required.</p>

    <form method="post" class="enrollment-form">
        <AntiforgeryToken />

        <div class="form-group">
            <label for="studentName">Full Name</label>
            <input type="text" id="studentName" name="Model.StudentName" value="@Model.StudentName" required maxlength="100" />
            @if (errors.ContainsKey(nameof(Model.StudentName)))
            {
                <span class="field-error">@errors[nameof(Model.StudentName)]</span>
            }
        </div>

        <div class="form-group">
            <label for="studentId">Student ID</label>
            <input type="text" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g. ABC12345" />
            <small>6–10 alphanumeric characters (uppercase letters and digits)</small>
            @if (errors.ContainsKey(nameof(Model.StudentId)))
            {
                <span class="field-error">@errors[nameof(Model.StudentId)]</span>
            }
        </div>

        <div class="form-group">
            <label for="courseId">Course</label>
            <select id="courseId" name="Model.CourseId" required>
                <option value="0">-- Select a course --</option>
                @foreach (var course in allCourses)
                {
                    <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.CourseCode — @course.Title</option>
                }
            </select>
            @if (errors.ContainsKey(nameof(Model.CourseId)))
            {
                <span class="field-error">@errors[nameof(Model.CourseId)]</span>
            }
        </div>

        <button type="submit" class="btn-submit">Submit Enrollment Request</button>
    </form>
}

@code {
    [SupplyParameterFromForm] public EnrollmentRequest Model { get; set; } = new();
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private List<Course> allCourses = [];
    private Dictionary<string, string> errors = new();
    private bool submitted;
    private string selectedCourseName = string.Empty;

    protected override void OnInitialized()
    {
        allCourses = Catalog.GetCourses();

        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    protected override void OnParametersSet()
    {
        if (HttpMethods.IsPost(HttpContextAccessor?.HttpContext?.Request.Method ?? "GET"))
        {
            ValidateAndSubmit();
        }
    }

    [CascadingParameter] public HttpContext? HttpContextAccessor { get; set; }

    private void ValidateAndSubmit()
    {
        errors.Clear();

        if (string.IsNullOrWhiteSpace(Model.StudentName))
            errors[nameof(Model.StudentName)] = "Name is required.";

        if (string.IsNullOrWhiteSpace(Model.StudentId))
            errors[nameof(Model.StudentId)] = "Student ID is required.";
        else if (!System.Text.RegularExpressions.Regex.IsMatch(Model.StudentId, @"^[A-Z0-9]{6,10}$"))
            errors[nameof(Model.StudentId)] = "Student ID must be 6–10 uppercase alphanumeric characters.";

        if (Model.CourseId <= 0)
            errors[nameof(Model.CourseId)] = "Please select a course.";

        if (errors.Count == 0)
        {
            var course = Catalog.GetCourse(Model.CourseId);
            selectedCourseName = course is not null ? $"{course.CourseCode} — {course.Title}" : "Unknown";
            submitted = true;
        }
    }
}

