toolArgs.file_text:
@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="/courses" class="filter-bar">
    <input type="text" name="search" value="@Search" placeholder="Search courses, codes, or instructors..." class="search-input" />
    <select name="departmentId" class="dept-select">
        <option value="">All Departments</option>
        @foreach (var dept in departments)
        {
            <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
        }
    </select>
    <button type="submit" class="btn-search">Search</button>
</form>

@if (courses.Count == 0)
{
    <p class="no-results">No courses found matching your criteria.</p>
}
else
{
    <div class="course-list">
        @foreach (var course in courses)
        {
            <div class="course-row">
                <div class="course-info">
                    <span class="course-code">@course.CourseCode</span>
                    <a href="/courses/@course.Id" class="course-title">@course.Title</a>
                    <span class="course-dept">@course.DepartmentName</span>
                </div>
                <div class="course-details">
                    <span>@course.Credits credits</span>
                    <span>@course.InstructorName</span>
                    <span>@course.Schedule</span>
                </div>
            </div>
        }
    </div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = [];
    private List<Course> courses = [];

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}

