::deep .form-intro {
    color: #555;
    margin-bottom: 1.5rem;
}

::deep .enrollment-form {
    max-width: 500px;
}

::deep .form-group {
    margin-bottom: 1.25rem;
}

::deep .form-group label {
    display: block;
    font-weight: 600;
    margin-bottom: 0.35rem;
    color: #333;
}

::deep .form-group input,
::deep .form-group select {
    width: 100%;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.95rem;
}

::deep .form-group small {
    display: block;
    margin-top: 0.25rem;
    color: #888;
    font-size: 0.8rem;
}

::deep .field-error {
    display: block;
    margin-top: 0.25rem;
    color: #c62828;
    font-size: 0.85rem;
}

::deep .btn-submit {
    padding: 0.65rem 1.5rem;
    background-color: #1a237e;
    color: white;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 1rem;
    font-weight: 500;
}

::deep .btn-submit:hover {
    background-color: #283593;
}

::deep .success-message {
    background: #e8f5e9;
    border: 1px solid #a5d6a7;
    border-radius: 8px;
    padding: 1.5rem;
    max-width: 500px;
}

::deep .success-message h2 {
    color: #2e7d32;
    margin: 0 0 0.75rem;
}

::deep .success-message p {
    margin: 0.5rem 0;
}

::deep .success-message a {
    display: inline-block;
    margin-top: 1rem;
    color: #1a237e;
    font-weight: 500;
    text-decoration: none;
}

::deep .success-message a:hover {
    text-decoration: underline;
}

